  "title": "Codex CLI agent run structured output",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "agent_role",
    "agent_id",
    "mode",
    "started_at",
    "completed_at",
    "status",
    "scope",
    "canonical_write_policy",
