  "properties": {
    "schema_version": {
      "type": "string",
      "const": "1.0.0"
    },
    "record_type": {
      "type": "string",
      "const": "agent_run"
    },
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
    },
    "agent_role": {
      "type": "string",
      "enum": [
        "triage_agent",
        "search_agent",
        "screening_agent",
        "dedupe_linker_agent",
        "extraction_agent",
        "trial_registry_agent",
        "classification_agent",
        "risk_of_bias_agent",
        "synthesis_agent",
        "review_agent",
        "supervisor_agent",
        "self_healing_agent",
        "release_agent"
      ]
    },
    "agent_id": {
      "type": "string"
    },
    "mode": {
      "type": "string",
      "enum": [
        "bootstrap",
        "surveillance",
        "coverage_repair",
        "extraction_refresh",
        "synthesis_refresh",
        "agent_directed"
      ]
    },
    "started_at": {
      "type": "string"
    },
    "completed_at": {
      "type": "string"
    },
    "status": {
      "type": "string",
      "enum": [
        "succeeded",
        "partial",
        "failed",
        "blocked"
      ]
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "question",
        "hallmark_ids",
        "track_ids",
        "intervention_ids"
      ],
      "properties": {
        "question": {
          "type": "string"
        },
        "hallmark_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        },
        "track_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        },
        "intervention_ids": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
          }
        }
      }
    },
    "canonical_write_policy": {
      "type": "string",
      "enum": [
        "no_canonical_writes",
        "candidate_change_required"
      ]
    },
    "execution": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "surface",
        "isolation",
        "workspace_path",
        "prompt_file",
        "prompt_template_file",
        "job_file",
        "output_schema_path",
        "output_path",
        "jsonl_log_path",
        "sandbox",
        "approval_policy"
      ],
      "properties": {
        "surface": {
          "type": "string",
          "enum": [
            "interactive_session",
            "codex_exec",
            "codex_cloud",
            "github_action",
            "other"
          ]
        },
        "isolation": {
          "type": "string",
          "enum": [
            "foreground_checkout",
            "git_worktree",
