  return (
    review.status === "complete" &&
    review.verdict === "accept" &&
    review.blocking === false &&
    !hasOpenMajorOrCriticalFinding(review)
  );
}

function reviewRecordsForCandidate(recordIndex, candidate) {
  return (candidate.evidence_review_ids ?? [])
